import UIKit
import CryptoKit

class Wallet {
    var privateKey: Curve25519.Signing.PrivateKey?
    var publicKey: Curve25519.Signing.PublicKey?
    
    init() {
        generateKeyPair()
    }
    
    func generateKeyPair() {
        privateKey = Curve25519.Signing.PrivateKey()
        publicKey = privateKey?.publicKey
    }
    
    func signTransaction(data: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        return try? privateKey.signature(for: data)
    }
    
    func getPublicKey() -> String? {
        return publicKey?.rawRepresentation.base64EncodedString()
    }
}

class BlockchainService {
    let baseURL = "https://api.blockchain.com/v3/"
    
    func sendTransaction(transactionData: Data, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)send") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let json: [String: Any] = ["transaction": transactionData.base64EncodedString()]
        request.httpBody = try? JSONSerialization.data(withJSONObject: json)
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            completion(.success("Transaction sent successfully"))
        }
        task.resume()
    }
}

class WalletViewController: UIViewController {
    var wallet = Wallet()
    var blockchainService = BlockchainService()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        print("Public Key: \(wallet.getPublicKey() ?? "No Public Key")")
    }
    
    func createAndSendTransaction() {
        let transactionData = "Sample transaction data".data(using: .utf8)!
        if let signature = wallet.signTransaction(data: transactionData) {
            blockchainService.sendTransaction(transactionData: signature) { result in
                switch result {
                case .success(let message):
                    print(message)
                case .failure(let error):
                    print("Error: \(error.localizedDescription)")
                }
            }
        }
    }
}